parameters.query:
={{ (() => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const offset = cfg.runtime.timeOffsetMinutes || 0;
  const nowOffset = `now() + interval '${offset} minutes'`;
  return `
    WITH next_call AS (
      SELECT c.cedula, timezone('${cfg.policy.TZ}', ${nowOffset}) as now_local
      FROM ${cfg.db.schema}.${cfg.db.table} c
      WHERE c.estado_flujo IN ('${cfg.states.pending}', '${cfg.states.retry}')
        AND (c.fecha_reagenda IS NULL OR c.fecha_reagenda <= ${nowOffset})
      ORDER BY c.intentos_llamada ASC, c.fecha_reagenda ASC NULLS FIRST
      LIMIT 1
      FOR UPDATE SKIP LOCKED
    )
    UPDATE ${cfg.db.schema}.${cfg.db.table} c
    SET estado_flujo = '${cfg.states.inProgress}',
        updated_at = ${nowOffset}
    FROM next_call nc
    WHERE c.cedula = nc.cedula
    RETURNING c.*;
  `;
})() }}

